141→// Run compiles and runs a .nyan file.
142→func (c *Compiler) Run(nyanPath string) error {
143→	tmpBin, err := os.CreateTemp("", "meow-run-*")
144→	if err != nil {
145→		return err
146→	}
147→	tmpBin.Close()
148→	defer os.Remove(tmpBin.Name())
149→
150→	if err := c.Build(nyanPath, tmpBin.Name()); err != nil {
151→		return err
152→	}
153→
154→	cmd := exec.Command(tmpBin.Name())
155→	cmd.Stdout = os.Stdout
156→	cmd.Stderr = os.Stderr
157→	cmd.Stdin = os.Stdin
158→	return cmd.Run()
159→}
