161→// CompileTestToGo compiles a .nyan file to Go source in test mode.
162→func (c *Compiler) CompileTestToGo(source, filename string) (string, error) {
163→	// First pass: extract catwalk output expectations from comments.
164→	c.logger.Debug("extracting catwalk outputs", "file", filename)
165→	l1 := lexer.New(source, filename)
166→	catwalkOutputs := codegen.ExtractCatwalkOutputs(l1.Tokens())
167→
168→	// Second pass: normal lex + parse.
169→	c.logger.Debug("lexing", "file", filename)
170→	l := lexer.New(source, filename)
171→
172→	c.logger.Debug("parsing", "file", filename)
173→	p := parser.New(l.Tokens())
174→	prog, errs := p.Parse()
175→	if len(errs) > 0 {
176→		var msgs []string
177→		for _, e := range errs {
178→			msgs = append(msgs, e.Error())
179→		}
180→		return "", fmt.Errorf("%s", strings.Join(msgs, "\n"))
181→	}
182→
183→	c.logger.Debug("type checking", "file", filename)
184→	ch := checker.New()
185→	typeInfo, typeErrs := ch.Check(prog)
186→	if len(typeErrs) > 0 {
187→		var msgs []string
188→		for _, e := range typeErrs {
189→			msgs = append(msgs, e.Error())
190→		}
191→		return "", fmt.Errorf("%s", strings.Join(msgs, "\n"))
192→	}
193→
194→	c.logger.Debug("generating test Go code", "file", filename)
195→	gen := codegen.NewTest()
196→	gen.SetTypeInfo(typeInfo)
197→	if c.coverEnabled {
198→		gen.EnableCoverage(filename)
199→	}
200→	if len(catwalkOutputs) > 0 {
201→		gen.SetCatwalkOutput(catwalkOutputs)
202→	}
203→	raw, err := gen.GenerateTest(prog)
204→	if err != nil {
205→		return "", err
206→	}
207→	formatted, err := format.Source([]byte(raw))
208→	if err != nil {
209→		return raw, nil
210→	}
211→	return string(formatted), nil
212→}
