282→// CompileFuzzToGo compiles a .nyan file to fuzz test Go source.
283→// Returns helper code and fuzz test code separately.
284→func (c *Compiler) CompileFuzzToGo(source, filename string) (helpers, fuzzTests string, fuzzNames []string, err error) {
285→	c.logger.Debug("lexing", "file", filename)
286→	l := lexer.New(source, filename)
287→
288→	c.logger.Debug("parsing", "file", filename)
289→	p := parser.New(l.Tokens())
290→	prog, errs := p.Parse()
291→	if len(errs) > 0 {
292→		var msgs []string
293→		for _, e := range errs {
294→			msgs = append(msgs, e.Error())
295→		}
296→		return "", "", nil, fmt.Errorf("%s", strings.Join(msgs, "\n"))
297→	}
298→
299→	c.logger.Debug("type checking", "file", filename)
300→	ch := checker.New()
301→	typeInfo, typeErrs := ch.Check(prog)
302→	if len(typeErrs) > 0 {
303→		var msgs []string
304→		for _, e := range typeErrs {
305→			msgs = append(msgs, e.Error())
306→		}
307→		return "", "", nil, fmt.Errorf("%s", strings.Join(msgs, "\n"))
308→	}
309→
310→	c.logger.Debug("generating fuzz Go code", "file", filename)
311→	gen := codegen.New()
312→	gen.SetTypeInfo(typeInfo)
313→	helpers, fuzzTests, fuzzNames, err = gen.GenerateFuzz(prog)
314→	if err != nil {
315→		return "", "", nil, err
316→	}
317→
318→	if formatted, fmtErr := format.Source([]byte(helpers)); fmtErr == nil {
319→		helpers = string(formatted)
320→	}
321→	if formatted, fmtErr := format.Source([]byte(fuzzTests)); fmtErr == nil {
322→		fuzzTests = string(formatted)
323→	}
324→	return helpers, fuzzTests, fuzzNames, nil
325→}
