327→// RunFuzz compiles a .nyan file and runs Go fuzz testing.
328→// Each fuzz_ function in the file is executed individually.
329→func (c *Compiler) RunFuzz(nyanPath, fuzzTime string) error {
330→	source, err := os.ReadFile(nyanPath)
331→	if err != nil {
332→		return fmt.Errorf("Hiss! Cannot read %s, nya~: %w", nyanPath, err)
333→	}
334→
335→	helpers, fuzzTests, fuzzNames, err := c.CompileFuzzToGo(string(source), filepath.Base(nyanPath))
336→	if err != nil {
337→		return err
338→	}
339→
340→	if len(fuzzNames) == 0 {
341→		return fmt.Errorf("Hiss! No fuzz_ functions found in %s, nya~", nyanPath)
342→	}
343→
344→	tmpDir, err := os.MkdirTemp("", "meow-fuzz-*")
345→	if err != nil {
346→		return fmt.Errorf("Hiss! Cannot create temp dir, nya~: %w", err)
347→	}
348→	defer os.RemoveAll(tmpDir)
349→
350→	if err := os.WriteFile(filepath.Join(tmpDir, "main.go"), []byte(helpers), 0644); err != nil {
351→		return fmt.Errorf("Hiss! Cannot write main.go, nya~: %w", err)
352→	}
353→	if err := os.WriteFile(filepath.Join(tmpDir, "main_test.go"), []byte(fuzzTests), 0644); err != nil {
354→		return fmt.Errorf("Hiss! Cannot write main_test.go, nya~: %w", err)
355→	}
356→
357→	modRoot := c.findModuleRoot()
358→	goVersion := readGoVersion(filepath.Join(modRoot, "go.mod"))
359→	modContent := fmt.Sprintf("module meow_build\n\ngo %s\n\nrequire github.com/135yshr/meow v0.0.0\n\nreplace github.com/135yshr/meow => %s\n", goVersion, modRoot)
360→	if err := os.WriteFile(filepath.Join(tmpDir, "go.mod"), []byte(modContent), 0644); err != nil {
361→		return fmt.Errorf("Hiss! Cannot write go.mod, nya~: %w", err)
362→	}
363→
364→	tidyCmd := exec.Command("go", "mod", "tidy")
365→	tidyCmd.Dir = tmpDir
366→	tidyCmd.Stderr = os.Stderr
367→	if err := tidyCmd.Run(); err != nil {
368→		return fmt.Errorf("Hiss! go mod tidy failed, nya~: %w", err)
369→	}
370→
371→	if fuzzTime == "" {
372→		fuzzTime = "10s"
373→	}
374→
375→	// Run each fuzz function individually (Go requires -fuzz to match exactly one target)
376→	for _, name := range fuzzNames {
377→		c.logger.Debug("running fuzz", "target", name, "fuzztime", fuzzTime)
378→		fmt.Fprintf(os.Stdout, "  --- %s ---\n", name)
379→		cmd := exec.Command("go", "test", fmt.Sprintf("-fuzz=^%s$", name), fmt.Sprintf("-fuzztime=%s", fuzzTime))
380→		cmd.Dir = tmpDir
381→		cmd.Stdout = os.Stdout
382→		cmd.Stderr = os.Stderr
383→		if err := cmd.Run(); err != nil {
384→			return fmt.Errorf("Hiss! fuzz %s failed, nya~: %w", name, err)
385→		}
386→	}
387→	return nil
388→}
