413→// RunMutationTest runs mutation testing on a source file using the given test files.
414→func (c *Compiler) RunMutationTest(sourcePath string, testPaths []string) error {
415→	// Read and parse the source file
416→	source, err := os.ReadFile(sourcePath)
417→	if err != nil {
418→		return fmt.Errorf("Hiss! Cannot read %s, nya~: %w", sourcePath, err)
419→	}
420→
421→	l := lexer.New(string(source), filepath.Base(sourcePath))
422→	p := parser.New(l.Tokens())
423→	prog, errs := p.Parse()
424→	if len(errs) > 0 {
425→		var msgs []string
426→		for _, e := range errs {
427→			msgs = append(msgs, e.Error())
428→		}
429→		return fmt.Errorf("%s", strings.Join(msgs, "\n"))
430→	}
431→
432→	// Enumerate mutations
433→	mutants := mutation.Enumerate(prog)
434→	if len(mutants) == 0 {
435→		fmt.Println("No mutations found, nya~")
436→		return nil
437→	}
438→	fmt.Printf("Found %d mutations, nya~\n", len(mutants))
439→
440→	// Parse test files and combine ASTs (source AST nodes are shared so mutant closures remain valid)
441→	combinedProg := &ast.Program{Stmts: append([]ast.Stmt{}, prog.Stmts...)}
442→	for _, tp := range testPaths {
443→		data, err := os.ReadFile(tp)
444→		if err != nil {
445→			return fmt.Errorf("Hiss! Cannot read %s, nya~: %w", tp, err)
446→		}
447→		tl := lexer.New(string(data), filepath.Base(tp))
448→		tparser := parser.New(tl.Tokens())
449→		testProg, testErrs := tparser.Parse()
450→		if len(testErrs) > 0 {
451→			var msgs []string
452→			for _, e := range testErrs {
453→				msgs = append(msgs, e.Error())
454→			}
455→			return fmt.Errorf("%s", strings.Join(msgs, "\n"))
456→		}
457→		combinedProg.Stmts = append(combinedProg.Stmts, testProg.Stmts...)
458→	}
459→
460→	// Build schema using source-only mutants to avoid mutating test code
461→	schema := mutation.BuildSchema(combinedProg, mutants)
462→
463→	// Generate mutated test binary
464→	gen := codegen.NewTest()
465→	gen.SetMutations(schema)
466→	raw, err := gen.GenerateTest(combinedProg)
467→	if err != nil {
468→		return err
469→	}
470→
471→	formatted, fmtErr := format.Source([]byte(raw))
472→	if fmtErr != nil {
473→		formatted = []byte(raw)
474→	}
475→
476→	// Build the mutated binary
477→	tmpDir, err := os.MkdirTemp("", "meow-mutate-*")
478→	if err != nil {
479→		return fmt.Errorf("Hiss! Cannot create temp dir, nya~: %w", err)
480→	}
481→	defer os.RemoveAll(tmpDir)
482→
483→	if err := os.WriteFile(filepath.Join(tmpDir, "main.go"), formatted, 0644); err != nil {
484→		return fmt.Errorf("Hiss! Cannot write Go source, nya~: %w", err)
485→	}
486→
487→	modRoot := c.findModuleRoot()
488→	goVersion := readGoVersion(filepath.Join(modRoot, "go.mod"))
489→	modContent := fmt.Sprintf("module meow_build\n\ngo %s\n\nrequire github.com/135yshr/meow v0.0.0\n\nreplace github.com/135yshr/meow => %s\n", goVersion, modRoot)
490→	if err := os.WriteFile(filepath.Join(tmpDir, "go.mod"), []byte(modContent), 0644); err != nil {
491→		return fmt.Errorf("Hiss! Cannot write go.mod, nya~: %w", err)
492→	}
493→
494→	tidyCmd := exec.Command("go", "mod", "tidy")
495→	tidyCmd.Dir = tmpDir
496→	tidyCmd.Stderr = os.Stderr
497→	if err := tidyCmd.Run(); err != nil {
498→		return fmt.Errorf("Hiss! go mod tidy failed, nya~: %w", err)
499→	}
500→
501→	binPath := filepath.Join(tmpDir, "mutant_test")
502→	buildCmd := exec.Command("go", "build", "-o", binPath, ".")
503→	buildCmd.Dir = tmpDir
504→	buildCmd.Stderr = os.Stderr
505→	if err := buildCmd.Run(); err != nil {
506→		return fmt.Errorf("Hiss! go build failed, nya~: %w", err)
507→	}
508→
509→	// Run mutation tests
510→	runner := mutation.NewRunner(binPath, 10*time.Second)
511→	results := runner.RunAll(mutants)
512→
513→	// Report
514→	mutation.Report(os.Stdout, mutants, results)
515→	return nil
516→}
