518→// readGoVersion parses a go.mod file and returns the Go version directive.
519→// Falls back to "1.26" if the file cannot be read or parsed.
520→func readGoVersion(path string) string {
521→	data, err := os.ReadFile(path)
522→	if err != nil {
523→		return "1.26"
524→	}
525→	for _, line := range strings.Split(string(data), "\n") {
526→		line = strings.TrimSpace(line)
527→		if strings.HasPrefix(line, "go ") {
528→			return strings.TrimPrefix(line, "go ")
529→		}
530→	}
531→	return "1.26"
532→}
