534→// companionSourcePath returns the inferred source file path for a test file.
535→// e.g. "testdata/math_test.nyan" → "testdata/math.nyan"
536→func companionSourcePath(testPath string) string {
537→	dir := filepath.Dir(testPath)
538→	base := filepath.Base(testPath)
539→	if !strings.HasSuffix(base, "_test.nyan") {
540→		return ""
541→	}
542→	name := strings.TrimSuffix(base, "_test.nyan")
543→	return filepath.Join(dir, name+".nyan")
544→}
