546→func (c *Compiler) findModuleRoot() string {
547→	// Walk up from executable to find go.mod
548→	dir, _ := os.Getwd()
549→	for {
550→		if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
551→			return dir
552→		}
553→		parent := filepath.Dir(dir)
554→		if parent == dir {
555→			break
556→		}
557→		dir = parent
558→	}
559→	// fallback
560→	return "."
561→}
